"""Shared Langfuse client and prompt body resolution."""

from __future__ import annotations

import time
from collections import OrderedDict
from collections.abc import Callable
from dataclasses import dataclass, field
from typing import Any, Protocol, cast

from agents.langfuse_config import LangfusePromptOptions, load_langfuse_prompt_options

LangfuseCredentials = tuple[str, str, str]

DEFAULT_SESSION_INSTRUCTIONS_CACHE_MAX_ENTRIES = 1000

_client: object | None = None
_client_credentials: LangfuseCredentials | None = None


class LangfusePromptClient(Protocol):
    def get_prompt(
        self,
        name: str,
        *,
        label: str,
        cache_ttl_seconds: int | None = None,
    ) -> object: ...


@dataclass
class SessionInstructionsCache:
    """LRU cache for per-session Langfuse instruction bodies (injected at composition root)."""

    max_entries: int = DEFAULT_SESSION_INSTRUCTIONS_CACHE_MAX_ENTRIES
    _entries: OrderedDict[str, tuple[float, str]] = field(default_factory=OrderedDict, repr=False)

    def get(self, key: str) -> tuple[float, str] | None:
        entry = self._entries.get(key)
        if entry is not None:
            self._entries.move_to_end(key)
        return entry

    def set(self, key: str, fetched_at: float, text: str) -> None:
        self._entries[key] = (fetched_at, text)
        self._entries.move_to_end(key)
        while len(self._entries) > self.max_entries:
            self._entries.popitem(last=False)


def prompt_text(
    client: LangfusePromptClient,
    name: str,
    *,
    label: str,
    cache_ttl_seconds: int,
    variables: dict[str, str] | None = None,
) -> str:
    """Return prompt body text; propagate Langfuse errors (no local fallback)."""
    prompt_obj = client.get_prompt(name, label=label, cache_ttl_seconds=cache_ttl_seconds)
    if isinstance(prompt_obj, str):
        body = prompt_obj
    else:
        body = ""
        for attr in ("prompt", "text", "content"):
            value = getattr(prompt_obj, attr, None)
            if isinstance(value, str) and value.strip():
                body = value
                break
        if not body:
            compile_fn = getattr(prompt_obj, "compile", None)
            if callable(compile_fn):
                compiled = compile_fn(**variables) if variables else compile_fn()
                if isinstance(compiled, str) and compiled.strip():
                    body = compiled
    if variables and body and "{{" in body:
        for key, value in variables.items():
            body = body.replace(f"{{{{{key}}}}}", value)
    if body.strip():
        return body
    raise ValueError(f"Langfuse prompt {name!r} label {label!r} has no usable text body")


def build_langfuse_client(
    *,
    public_key: str,
    secret_key: str,
    base_url: str,
) -> LangfusePromptClient:
    from langfuse import Langfuse

    return cast(
        LangfusePromptClient,
        Langfuse(
            public_key=public_key,
            secret_key=secret_key,
            host=base_url.rstrip("/"),
        ),
    )


def get_langfuse_client(
    *,
    public_key: str,
    secret_key: str,
    base_url: str,
) -> LangfusePromptClient:
    """Return a process-wide Langfuse client for the given credentials."""
    global _client, _client_credentials
    creds: LangfuseCredentials = (public_key, secret_key, base_url.rstrip("/"))
    if _client is None or _client_credentials != creds:
        _client = build_langfuse_client(
            public_key=public_key,
            secret_key=secret_key,
            base_url=base_url,
        )
        _client_credentials = creds
    return cast(LangfusePromptClient, _client)


def reset_langfuse_client_for_tests() -> None:
    """Clear the shared client (unit tests only)."""
    global _client, _client_credentials
    _client = None
    _client_credentials = None


def resolve_prompt_options(
    *,
    label: str | None = None,
    cache_ttl_seconds: int | None = None,
) -> LangfusePromptOptions:
    """Merge explicit options with LANGFUSE_PROMPT_* environment defaults."""
    env = load_langfuse_prompt_options()
    return LangfusePromptOptions(
        label=label if label is not None else env.label,
        cache_ttl_seconds=(
            cache_ttl_seconds if cache_ttl_seconds is not None else env.cache_ttl_seconds
        ),
    )


def resolve_langfuse_session_id(
    *,
    agent: Any = None,
    team: Any = None,
    run_context: Any = None,
) -> str:
    """Best-effort session id for per-session Langfuse instruction caching."""
    if run_context is not None:
        session_id = getattr(run_context, "session_id", None)
        if session_id:
            return str(session_id)
    for entity in (agent, team):
        if entity is not None:
            session_id = getattr(entity, "session_id", None)
            if session_id:
                return str(session_id)
    return "_default"


def session_langfuse_instructions(
    *,
    cache: SessionInstructionsCache,
    cache_key: str,
    fetch_text: Callable[[], str],
    cache_ttl_seconds: int | None = None,
) -> Callable[..., str]:
    """Return Agno ``instructions`` callable that loads Langfuse text once per session.

    Re-fetches when ``LANGFUSE_PROMPT_CACHE_TTL_SECONDS`` elapses since the last fetch
    for the same session (in addition to the Langfuse SDK's own ``cache_ttl_seconds``).
    """

    ttl = (
        cache_ttl_seconds
        if cache_ttl_seconds is not None
        else load_langfuse_prompt_options().cache_ttl_seconds
    )

    def instructions(
        agent: Any = None,
        team: Any = None,
        session_state: dict[str, Any] | None = None,
        run_context: Any = None,
    ) -> str:
        del session_state  # Agno passes this; we key on session_id only.
        session_id = resolve_langfuse_session_id(agent=agent, team=team, run_context=run_context)
        full_key = f"{cache_key}:{session_id}"
        now = time.monotonic()
        cached = cache.get(full_key)
        if cached is not None:
            fetched_at, text = cached
            if ttl > 0 and now - fetched_at < ttl:
                return text
        text = fetch_text()
        cache.set(full_key, now, text)
        return text

    return instructions

